 */
function requestLogger(req, res, next) {
  const start = Date.now();

  // Log on response finish
  res.on('finish', () => {
    // Skip health checks, static files, and admin polling endpoints
    if (req.path === '/health' || !req.path.startsWith('/api')) return;
